						<string name="Name">Script</string>
						<ProtectedString name="Source">-- (Hat Giver Script - Loaded.)

debounce = true

function onTouched(hit)
	if (hit.Parent:findFirstChild(&quot;Humanoid&quot;) ~= nil and debounce == true) then
		debounce = false
		h = Instance.new(&quot;Hat&quot;)
		p = Instance.new(&quot;Part&quot;)
		h.Name = &quot;Shades&quot;
		p.Parent = h
		p.Position = hit.Parent:findFirstChild(&quot;Head&quot;).Position
		p.Name = &quot;Handle&quot; 
		p.formFactor = 0
		p.Size = Vector3.new(2, 1, 1) 
		p.BottomSurface = 0 
		p.TopSurface = 0 
		p.Locked = true 
                p.Reflectance = .3
                p.Transparency = .1
		script.Parent.Mesh:clone().Parent = p
		h.Parent = hit.Parent
		h.AttachmentPos = Vector3.new(0, 0.3, 0.2)
		wait(5)
		debounce = true
	end
end

script.Parent.Touched:connect(onTouched)

-- Proof to kewlmaiaII</ProtectedString>
